import urllib.request, json, time

etfs = ['SPYM', 'SCHG', 'DYNF', 'CGGR', 'SPHQ', 'XLG', 'AIQ', 'SOXQ', 'PSI']
etf_prices = {}
for etf in etfs:
    time.sleep(0.5)
    url = f'https://query2.finance.yahoo.com/v8/finance/chart/{etf}?interval=1d&range=5d'
    req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
    try:
        data = json.loads(urllib.request.urlopen(req).read())
        closes = data['chart']['result'][0]['indicators']['quote'][0]['close']
        current = closes[-1]
        prev = closes[-2] if len(closes) > 1 else current
        chg = (current - prev) / prev * 100 if prev else 0
        etf_prices[etf] = {'price': round(current, 2), 'change': round(chg, 2)}
    except Exception as e:
        etf_prices[etf] = {'error': str(e)}

for k, v in etf_prices.items():
    print(f'{k}: {v}')
